  seer: 'voice_seer_sibylle',
  strongman: 'voice_strongman_hercule',
  werewolf: 'voice_werewolf'
};"}, {"path": "src/generated/circus-werewolf/elimination.ts", "purpose": "Format elimination announcements as cancelled acts.", "content": "export function formatElimination(artistName: string, actName: string): string {
