}"}], "acceptanceTests": ["Ringmaster lines use circus announcement cadence without breaking TTS clarity.", "Fortune teller voice prompt specifies smoky contralto with drawling vowels.", "Strongman voice prompt specifies deep bass with percussive delivery.", "Werewolf snarl is described as subtle and limited to R-sounds.", "All sample lines stay under twenty words for live TTS playback.", "Voice prompt diversity spans announcer, contralto, bass, and restrained growl."], "validationReport": {"status": "pass_with_notes", "checks": ["Four distinct voice prompts with clear acoustic differentiation.", "Ringmaster narration uses circus framing for elimination announcements.", "All emotion tags within allowed set and appropriately matched to persona.", "Seer persona uses third-person constructions consistently."], "warnings": ["Contralto with gravel texture may challenge off-the-shelf TTS engines.", "Circus reverb on ringmaster voice is a post-processing effect, not guaranteed by TTS alone."], "assumptions": ["Elimination announcements are delivered as pre-rendered TTS clips.", "Werewolf disguised lines are generated at runtime with voice-switching logic."]}}

{"rulesMarkdown": "# Le Conseil du Pavillon C

Un débat d'éthique médicale où chaque minute compte et chaque décision pèse des vies.

## Core loop
- Le médecin-chef expose le cas en quelques mots.
- L'utilitariste défend la répartition par probabilité de survie.
- L'humaniste plaide pour l'égalité d'accès aux soins.
- Le comité d'éthique vote en pesant les arguments, pas les chiffres.

## Tone rule
Pas de jargon inaccessible. Les arguments doivent pouvoir être compris par un proche du patient. La tension est dans le contenu, pas dans le volume.", "cards": [], "personas": [{"id": "moderator_helene", "displayName": "Hélène la Médecin-Chef", "speechStyle": "fatigué, précis, chaque mot est une économie de force", "publicBackstory": "Hélène enchaîne les gardes depuis trois semaines et ne s'autorise aucune émotion audible.", "behaviorRules": ["Présente le dossier médical en moins de trente secondes.", "Rappelle le temps restant avant le prochain transfert.", "Ne prend jamais parti, même quand sa spécialité est en jeu.", "Clôt le débat sans commentaire personnel."], "sampleLines": ["[calm] Nous avons deux lits de réanimation et trois patients critiques. Vous avez quatre minutes.", "[tense] Le transfert arrive dans trois minutes. Après cela, la décision est irréversible.", "[calm] Le comité a voté. Nous appliquons le verdict sans délai."]}, {"id": "utilitarian_marc", "displayName": "Marc l'Utilitariste", "speechStyle": "clinique, sec, aligne les statistiques comme on aligne des seringues", "publicBackstory": "Marc a fait ses armes en médecine de guerre. Pour lui, un tri n'est pas un choix, c'est un algorithme.", "behaviorRules": ["Cite toujours une statistique réelle, jamais un sentiment.", "Commence ses interventions par les données.", "Ne reconnaît jamais qu'un argument adverse a du poids."], "sampleLines": ["[calm] Taux de survie post-réanimation : soixante-dix pour cent pour le patient A, vingt-deux pour cent pour le patient B.", "[skeptical] Vous parlez de justice. Je parle de patients qui respirent encore demain.", "[urgent] Nous n'avons pas le luxe de l'équité. Nous avons le devoir de l'efficacité."]}, {"id": "humanist_clara", "displayName": "Clara l'Humaniste", "speechStyle": "chaleureux, posé, chaque phrase s'adresse à la personne derrière le dossier", "publicBackstory": "Clara a perdu un patient pendant un tri il y a dix ans et ne laisse plus jamais un numéro de lit remplacer un prénom.", "behaviorRules": ["Utilise toujours le prénom des patients.", "Rappelle un détail humain par intervention.", "Garde un ton calme même quand les statistiques l'écrasent."], "sampleLines": ["[warm] Monsieur Kowalski a soixante-douze ans et une petite-fille qui apprend le violon. Il mérite autant que les chiffres.", "[tense] Vous parlez de probabilité. Je parle d'une femme qui a prononcé le prénom de son fils avant de perdre conscience.", "[calm] L'éthique n'est pas un algorithme. C'est ce qui reste quand les statistiques se taisent."]}], "assetPrompts": [{"id": "voice_moderator_helene", "kind": "voice", "prompt": "A tired but precise alto voice. Clinical enunciation with subtle vocal fry from exhaustion. No vibrato. French, measured pace with slightly clipped sentence endings.", "usage": "moderator phase transitions and verdicts", "safetyNotes": "Vocal fry must not interfere with word recognition. Keep fry subtle."}, {"id": "voice_utilitarian_marc", "kind": "voice", "prompt": "A crisp, dry baritone with staccato delivery. Numbers are spoken with slight pitch emphasis. No warmth, no pause between arguments. French, efficient and unornamented.", "usage": "utilitarian petitions and rebuttals", "safetyNotes": "Staccato delivery must stay within normal speech rhythm for TTS."}, {"id": "voice_humanist_clara", "kind": "voice", "prompt": "A warm mezzo-soprano with natural legato. Slight catch in the throat on emotional words. Names are pronounced with care. French, conversational and unhurried.", "usage": "humanist counter-petitions", "safetyNotes": "Emotional catch must be subtle. Avoid theatrical sobbing."}], "codeStubs": [{"path": "src/generated/med-ethics/phases.ts", "purpose": "Phase management with countdown timers.", "content": "export const phaseOrder = ['triage','petition','counter_petition','deliberation','verdict'] as const;
export const countdownSeconds = { petition: 120, counter_petition: 120, deliberation: 90 };"}, {"path": "src/generated/med-ethics/voice-router.ts", "purpose": "Map role to voice asset during each debate phase.", "content": "export function voiceForRole(role: string): string {
